import React, { useMemo, useState } from "react";
import {
  Search,
  ChevronDown,
  Plus,
  X,
  Check,
  FileText,
  ArrowUp,
  ArrowDown,
  Package,
  User,
  StickyNote,
  Paperclip,
  CalendarDays,
  Eye,
  Pencil,
  Trash2,
  SlidersHorizontal,
  CircleDollarSign,
  TrendingUp,
  Filter,
  MapPin,
  Truck,
  Hash
} from "lucide-react";

// --- Constants & Mock Data ---
const STATUSES = ["New", "In Transit", "Delivered", "Cancelled"];
const BILLING_STATUSES = ["Pending", "Invoiced", "Paid", "Factored"];
const BROKERS = ["XPO Logistics", "Echo Global", "Coyote Logistics", "CH Robinson", "Transplace"];
const DRIVERS_LIST = ["Xumotyun Baxriddinov", "Bobur Toshmatov", "Sardor Yusupov", "Jasur Mirzayev"];
const TRUCKS = ["TRK-001", "TRK-002", "TRK-003", "TRK-007"];
const TRAILERS = ["TRL-012", "TRL-023", "TRL-044", "TRL-055"];

const initialLoads = [
  { id: "LD-20241", date: "04/30/26", driver: "Xumotyun Baxriddinov", broker: "XPO Logistics", po: "PO-8821", pickup: "New York Mills, MN", delivery: "Brookland, AR", rate: "$2,480.00", status: "In Transit", billing: "Pending", attachments: 1 },
  { id: "LD-20235", date: "04/28/26", driver: "Bobur Toshmatov", broker: "Echo Global", po: "PO-8801", pickup: "Chicago, IL", delivery: "Dallas, TX", rate: "$1,840.00", status: "Delivered", billing: "Invoiced", attachments: 2 },
  { id: "LD-20228", date: "04/27/26", driver: "Sardor Yusupov", broker: "CH Robinson", po: "PO-8795", pickup: "Atlanta, GA", delivery: "Memphis, TN", rate: "$786.00", status: "Delivered", billing: "Paid", attachments: 0 },
];

// --- Utility Functions ---
const cn = (...classes) => classes.filter(Boolean).join(" ");

const emptyForm = () => ({
  status: "New",
  billingStatus: "Pending",
  pickupCity: "",
  pickupDate: "",
  deliveryCity: "",
  deliveryDate: "",
  broker: "",
  po: "",
  rate: "",
  driver: "",
  notes: "",
  attachments: [],
});

// --- UI Components ---
const StatCard = ({ label, value, icon: Icon, colorClass }) => (
  <div className="flex flex-1 min-w-[200px] items-center gap-4 rounded-2xl border border-slate-200 bg-white p-5 shadow-sm transition-all hover:shadow-md">
    <div className={cn("flex h-12 w-12 items-center justify-center rounded-xl", colorClass)}>
      <Icon className="h-6 w-6" />
    </div>
    <div>
      <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">{label}</p>
      <p className="text-2xl font-black text-slate-900">{value}</p>
    </div>
  </div>
);

const FormField = ({ label, children }) => (
  <div className="space-y-1.5">
    <label className="text-[12px] font-bold text-slate-500 uppercase tracking-tight ml-1">{label}</label>
    {children}
  </div>
);

const Input = (props) => (
  <input
    {...props}
    className={cn(
      "h-11 w-full rounded-xl border border-slate-200 bg-slate-50/50 px-4 text-sm text-slate-700 outline-none transition-all",
      "focus:border-blue-500 focus:bg-white focus:ring-4 focus:ring-blue-500/10 placeholder:text-slate-400",
      props.className
    )}
  />
);

const Select = (props) => (
  <select
    {...props}
    className={cn(
      "h-11 w-full rounded-xl border border-slate-200 bg-slate-50/50 px-4 text-sm text-slate-700 outline-none transition-all",
      "focus:border-blue-500 focus:bg-white focus:ring-4 focus:ring-blue-500/10",
      props.className
    )}
  />
);

const StatusBadge = ({ status }) => {
  const styles = {
    "In Transit": "bg-amber-50 text-amber-700 border-amber-100",
    "Delivered": "bg-emerald-50 text-emerald-700 border-emerald-100",
    "Paid": "bg-blue-50 text-blue-700 border-blue-100",
    "Pending": "bg-slate-100 text-slate-600 border-slate-200",
    "New": "bg-purple-50 text-purple-700 border-purple-100",
  };
  return (
    <span className={cn("px-2.5 py-1 rounded-lg text-[11px] font-bold border", styles[status] || "bg-slate-50 text-slate-500")}>
      {status}
    </span>
  );
};

// --- Main Page ---
export default function LoadsPage() {
  const [loads, setLoads] = useState(initialLoads);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState(emptyForm());
  const [search, setSearch] = useState("");

  const set = (key, value) => setForm((prev) => ({ ...prev, [key]: value }));

  const stats = useMemo(() => {
    const total = loads.reduce((sum, l) => sum + parseFloat(l.rate.replace(/[$,]/g, "") || 0), 0);
    const active = loads.filter(l => l.status !== "Delivered").length;
    return { total: total.toLocaleString(), active };
  }, [loads]);

  const filtered = loads.filter(l => 
    l.id.toLowerCase().includes(search.toLowerCase()) || 
    l.driver.toLowerCase().includes(search.toLowerCase())
  );

  const handleCreate = () => {
    const newLoad = {
      id: `LD-${Math.floor(10000 + Math.random() * 90000)}`,
      date: new Date().toLocaleDateString(),
      driver: form.driver || "Unassigned",
      broker: form.broker || "Private",
      po: form.po || "N/A",
      pickup: form.pickupCity || "Unknown",
      delivery: form.deliveryCity || "Unknown",
      rate: `$${parseFloat(form.rate || 0).toLocaleString()}`,
      status: form.status,
      billing: form.billingStatus,
      attachments: 0,
    };
    setLoads([newLoad, ...loads]);
    setShowForm(false);
    setForm(emptyForm());
  };

  return (
    <div className="min-h-screen bg-[#F1F5F9] p-4 lg:p-8 font-sans antialiased text-slate-900">

      {/* Header Section */}
      <div className="mx-auto max-w-7xl">
        <div className="mb-8 flex flex-col gap-6 lg:flex-row lg:items-end lg:justify-between">
          <div>
            <h1 className="text-3xl font-black tracking-tight text-slate-900">Fleet Dispatch</h1>
            <p className="text-slate-500 font-medium mt-1">Real-time logistics monitoring and load management.</p>
          </div>

          <div className="flex flex-wrap gap-4">
            <StatCard label="Total Revenue" value={`$${stats.total}`} icon={CircleDollarSign} colorClass="bg-emerald-50 text-emerald-600" />
            <StatCard label="Active Loads" value={stats.active} icon={TrendingUp} colorClass="bg-blue-50 text-blue-600" />
          </div>
        </div>

        {/* Toolbar */}
        <div className="mb-6 flex flex-wrap items-center justify-between gap-4">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" />
            <input
              type="text"
              placeholder="Search by ID or Driver..."
              className="h-12 w-full rounded-2xl border-none bg-white pl-12 pr-4 shadow-sm transition-all focus:ring-4 focus:ring-blue-500/10 outline-none"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>

          <button
            onClick={() => setShowForm(!showForm)}
            className={cn(
              "flex h-12 items-center gap-2 rounded-2xl px-6 text-sm font-bold transition-all active:scale-95 shadow-lg",
              showForm ? "bg-slate-800 text-white" : "bg-blue-600 text-white hover:bg-blue-700 hover:shadow-blue-200"
            )}
          >
            {showForm ? <X className="h-5 w-5" /> : <Plus className="h-5 w-5" />}
            {showForm ? "Close Form" : "Create New Load"}
          </button>
        </div>

        {/* Form Section */}
        {showForm && (
          <div className="mb-8 overflow-hidden rounded-3xl border border-slate-200 bg-white shadow-2xl animate-in fade-in slide-in-from-top-4 duration-300">
            <div className="p-8">
              <div className="grid grid-cols-1 gap-8 md:grid-cols-2 lg:grid-cols-3">

                {/* Logistics Info */}
                <div className="space-y-6">
                  <div className="flex items-center gap-2 text-blue-600 font-bold uppercase tracking-widest text-xs">
                    <Hash className="h-4 w-4" /> <span>General Info</span>
                  </div>
                  <FormField label="Broker">
                    <Select value={form.broker} onChange={e => set('broker', e.target.value)}>
                      <option>Select Broker</option>
                      {BROKERS.map(b => <option key={b}>{b}</option>)}
                    </Select>
                  </FormField>
                  <FormField label="Total Rate">
                    <Input placeholder="0.00" value={form.rate} onChange={e => set('rate', e.target.value)} />
                  </FormField>
                </div>

                {/* Route Info */}
                <div className="space-y-6">
                  <div className="flex items-center gap-2 text-orange-500 font-bold uppercase tracking-widest text-xs">
                    <MapPin className="h-4 w-4" /> <span>Route Details</span>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <FormField label="Pickup City">
                      <Input placeholder="City" value={form.pickupCity} onChange={e => set('pickupCity', e.target.value)} />
                    </FormField>
                    <FormField label="Pickup Date">
                      <Input type="date" value={form.pickupDate} onChange={e => set('pickupDate', e.target.value)} />
                    </FormField>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <FormField label="Delivery City">
                      <Input placeholder="City" value={form.deliveryCity} onChange={e => set('deliveryCity', e.target.value)} />
                    </FormField>
                    <FormField label="Delivery Date">
                      <Input type="date" value={form.deliveryDate} onChange={e => set('deliveryDate', e.target.value)} />
                    </FormField>
                  </div>
                </div>

                {/* Driver Info */}
                <div className="space-y-6">
                  <div className="flex items-center gap-2 text-purple-600 font-bold uppercase tracking-widest text-xs">
                    <Truck className="h-4 w-4" /> <span>Assignment</span>
                  </div>
                  <FormField label="Assign Driver">
                    <Select value={form.driver} onChange={e => set('driver', e.target.value)}>
                      <option>Select Driver</option>
                      {DRIVERS_LIST.map(d => <option key={d}>{d}</option>)}
                    </Select>
                  </FormField>
                  <FormField label="Current Status">
                    <Select value={form.status} onChange={e => set('status', e.target.value)}>
                      {STATUSES.map(s => <option key={s}>{s}</option>)}
                    </Select>
                  </FormField>
                </div>
              </div>

              <div className="mt-10 flex justify-end border-t pt-8">
                <button 
                  onClick={handleCreate}
                  className="rounded-2xl bg-blue-600 px-10 py-4 text-sm font-black text-white transition-all hover:bg-blue-700 hover:scale-[1.02] shadow-xl shadow-blue-100"
                >
                  Dispatch Load Now
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Table Section */}
        <div className="overflow-hidden rounded-3xl border border-slate-200 bg-white shadow-sm">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-separate border-spacing-0">
              <thead>
                <tr className="bg-slate-50/50">
                  {["Load Details", "Route", "Driver", "Rate", "Status", "Actions"].map((h) => (
                    <th key={h} className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400 border-b">
                      {h}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filtered.map((load) => (
                  <tr key={load.id} className="group transition-colors hover:bg-blue-50/30">
                    <td className="px-6 py-5">
                      <div className="flex flex-col">
                        <span className="font-mono text-xs font-black text-blue-600">{load.id}</span>
                        <span className="text-sm font-bold text-slate-900 mt-0.5">{load.broker}</span>
                        <span className="text-[11px] text-slate-400 font-medium">PO: {load.po}</span>
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      <div className="flex items-center gap-3">
                        <div className="flex flex-col items-center">
                          <div className="h-2 w-2 rounded-full bg-blue-500" />
                          <div className="h-6 w-0.5 bg-slate-200" />
                          <div className="h-2 w-2 rounded-full bg-orange-500" />
                        </div>
                        <div className="flex flex-col gap-1.5">
                          <span className="text-xs font-bold text-slate-700 leading-none">{load.pickup}</span>
                          <span className="text-xs font-bold text-slate-700 leading-none">{load.delivery}</span>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      <div className="flex items-center gap-3">
                        <div className="h-8 w-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold text-xs border border-slate-200">
                          {load.driver.charAt(0)}
                        </div>
                        <span className="text-sm font-bold text-slate-700">{load.driver}</span>
                      </div>
                    </td>
                    <td className="px-6 py-5 text-sm font-black text-slate-900">{load.rate}</td>
                    <td className="px-6 py-5"><StatusBadge status={load.status} /></td>
                    <td className="px-6 py-5">
                      <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-colors">
                          <Pencil className="h-4 w-4" />
                        </button>
                        <button className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-colors">
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          {filtered.length === 0 && (
            <div className="py-20 text-center">
              <Package className="h-12 w-12 text-slate-200 mx-auto mb-4" />
              <p className="text-slate-400 font-medium">No matching loads found.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
